import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Project {
  name: string;
  hours: number;
}

interface TimeTrackingData {
  todayLoggedHours: {
    total: number;
    goal: number;
    percentage: number;
  };
  projects: Project[];
}

export default function Widget() {
  const timeTrackingData = response.data as TimeTrackingData;
  const { todayLoggedHours, projects } = timeTrackingData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 420, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Time Logged Today
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1976D2' }}>
              {todayLoggedHours.total.toFixed(1)} hrs
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Goal: {todayLoggedHours.goal} hrs ({todayLoggedHours.percentage.toFixed(2)}%)
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: projects.map(project => project.hours),
                  color: ['#FF5722', '#03A9F4', '#FFC107'],
                  showLabel: true,
                  labelPosition: 'inside',
                  labelStyle: { fontSize: 10, fill: '#FFFFFF' },
                },
              ]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <PieChart />
              </g>
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={1}>
            {projects.map((project) => (
              <Box key={project.name} sx={{ flex: 1 }}>
                <Typography variant="caption" color="text.secondary">
                  {project.name}
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {project.hours.toFixed(1)} hrs
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
